#include <cstdint>
#include <iostream>

int main() {
    std::int64_t left{}, right{};
    if (!(std::cin >> left >> right)) return 1;
    std::int64_t sum = left + right;
    bool active = sum != 0;
    std::cout << (active ? "active " : "inactive ") << sum << '\n';
}
